INSERT INTO `honorarios_categorias` (`id`, `tipo`, `orden`, `otros`) VALUES (4, '4.Mensura con fraccionamiento', 0, '4.6 Mensuras con Unificacón y Fraccionamiento se considera solo como fraccionamiento a los efectos de Liquidación de Honorarios.  
INSERT INTO `honorarios_categorias` (`id`, `tipo`, `orden`, `otros`) VALUES (5, '5.Conjunto Inmobiliario', 0, 'Se considerará el total del ítem 4 que correspondiese, aumentado el total en un 20% (Haciendo a los fines del cálculo una parcela igual una U.F.)');
INSERT INTO `honorarios_categorias` (`id`, `tipo`, `orden`, `otros`) VALUES (6, '6.Mensura en Propiedad Horizontal', 0, '');
INSERT INTO `honorarios_categorias` (`id`, `tipo`, `orden`, `otros`) VALUES (7, '7.Mensura Rural', 0, 'Se Unifica el criterio, ya sea Mensura Simple con Fraccionamiento y Unificación. 
INSERT INTO `honorarios_categorias` (`id`, `tipo`, `orden`, `otros`) VALUES (8, '9.Relevamiento Planialtimétrico', 0, '');
