INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (1, 'Los precios incluyen: movilidad hasta 30 Km., sueldos, jornales y seguros de peones y ayudantes, mojones, equipamientos varios, dibujos y copias de planos, etc.', 1);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (2, 'Los precios no incluyen: tasas, derechos, impuestos y sellados varios.', 2);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (3, 'En todos los casos estos son precios mínimos, en propiedades de alto valor, deberán ser incrementados de acuerdo a sus precios.', 3);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (4, 'En casos no previstos el Consejo Directivo resolverá en la 1ra reunión posterior a la presentación.', 4);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (5, 'El monto por control de matrícula asciende al cinco por ciento (5%) de los montos indicados de la tabla referencial.', 5);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (6, 'El valor mínimo a depositar por control de matrícula asciende a pesos Siete Mil ($7.000,00).', 6);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (7, 'Tasa por sistema de Autoconsulta: Pesos Quinientos $ 500', 7);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (8, 'Cuota GEO FADA: Pesos Seiscientos $ 600', 8);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (9, 'La liquidación de las tasas se redondeará por exceso a la unidad mayor.', 9);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (10, 'A los fines del cómputo, se consideran rurales las parcelas mayores o igual a 12Ha y urbanas las menores a éstas.', 10);
INSERT INTO `honorarios_notas` (`id`, `contenido`, `orden`) VALUES (11, 'En caso de existir contratos con instituciones estatales se podrá abonar el 5% del valor del contrato, siempre que sea presentado ante el CPAM para su toma de conocimiento dentro de los 60 días de convenido el mismo. Transcurrido ese plazo se deberá abonar la tasa por visado según estipulado en la presente tabla.', 11);
